GraveFallGame.scene.Game.prototype.devCommandEnemyDamage=function(amount){var damage=parseInt(amount,10);if(isNaN(damage))return"Usage: gf.enemy.damage amount";this.devPrepareImmediateBattle();this.enemyHealthCurrent=Math.max(0,this.enemyHealthCurrent-Math.max(0,damage));this.updateEnemyHealthBarUi();this.updateEnemyDamageState();if(this.enemyHealthCurrent<=0){this.phase=GraveFallGame.scene.Game.PHASE_COMMAND;this.startEnemyDefeatedSequence();return"Enemy damage applied. Enemy defeated."}return"Enemy HP: "+
this.enemyHealthCurrent+"/"+this.enemyHealthMax};GraveFallGame.scene.Game.prototype.devCommandEnemyHp=function(amount){var hp=parseInt(amount,10);if(isNaN(hp))return"Usage: gf.enemy.hp amount";this.devPrepareImmediateBattle();this.enemyHealthCurrent=Math.max(0,Math.min(this.enemyHealthMax,hp));this.updateEnemyHealthBarUi();this.updateEnemyDamageState();return"Enemy HP set to "+this.enemyHealthCurrent+"/"+this.enemyHealthMax};
GraveFallGame.scene.Game.prototype.getDevPatternIds=function(){var enemies=GraveFallGame.scene.Game.ENEMIES||{};var seen={};var patterns=[];var enemyId;var i;var patternId;for(enemyId in enemies)if(enemies.hasOwnProperty(enemyId)&&enemies[enemyId].patterns)for(i=0;i<enemies[enemyId].patterns.length;i++){patternId=enemies[enemyId].patterns[i];if(seen[patternId]!==true){seen[patternId]=true;patterns.push(patternId)}}patterns.sort();return patterns};
GraveFallGame.scene.Game.prototype.resolveDevPatternId=function(patternId){var patterns=this.getDevPatternIds();var search=String(patternId||"").toLowerCase();var i;for(i=0;i<patterns.length;i++)if(patterns[i].toLowerCase()===search)return patterns[i];return null};GraveFallGame.scene.Game.prototype.devCommandPatternList=function(){return"Patterns:\n"+this.getDevPatternIds().join("\n")};
GraveFallGame.scene.Game.prototype.devEnsureActionPhaseForPatternTest=function(){this.devPrepareImmediateBattle();if(this.phase!==GraveFallGame.scene.Game.PHASE_ACTION){this.commandActionsResolved=true;this.phase=GraveFallGame.scene.Game.PHASE_ACTION;this.actionPhaseTimer=this.getActionPhaseDurationFrames(this.getCurrentEnemyConfig());this.nextPatternIn=999999;this.actionPhaseStartDelayFrames=0;this.clearProjectiles();this.setBattleArenaVisible(true);this.layoutBattleAvatarsInArena();this.turnTimerText.alpha=
0;for(var i=0;i<this.playerMenus.length;i++){this.playerMenus[i].container.y=this.playerMenus[i].confirmedY;this.playerMenus[i].hitCooldown=0;this.playerMenus[i].moveSpeed=this.calculateEffectiveMoveSpeed(this.playerMenus[i]);this.activateBattleAvatar(this.playerMenus[i])}}};
GraveFallGame.scene.Game.prototype.devCommandPatternSpawn=function(patternId,count){var resolvedId=this.resolveDevPatternId(patternId);var spawnCount=parseInt(count,10);var i;if(!resolvedId)return"Usage: gf.pattern.spawn patternId count\nType gf.pattern.list";if(isNaN(spawnCount)||spawnCount<1)spawnCount=1;spawnCount=Math.min(spawnCount,8);this.devEnsureActionPhaseForPatternTest();for(i=0;i<spawnCount;i++){this.playEnemyPatternSfx(resolvedId);this.spawnEnemyPatternById(resolvedId)}return"Spawned pattern "+
resolvedId+" x"+spawnCount};
GraveFallGame.scene.Game.prototype.resolveDevPlayers=function(target){var players=[];var search=String(target||"all").toLowerCase();var rawIndex;var index;var i;var menu;if(search==="all"||search==="party"||search==="everyone"){for(i=0;i<this.playerMenus.length;i++)players.push(this.playerMenus[i]);return players}rawIndex=parseInt(search,10);if(!isNaN(rawIndex)){index=rawIndex<=0?0:rawIndex-1;if(this.playerMenus[index])players.push(this.playerMenus[index]);return players}for(i=0;i<this.playerMenus.length;i++){menu=
this.playerMenus[i];if(menu.characterId&&menu.characterId.toLowerCase()===search||menu.characterName&&menu.characterName.toLowerCase()===search){players.push(menu);return players}}return players};GraveFallGame.scene.Game.prototype.devRefreshPlayersAfterHealthChange=function(players){var i;for(i=0;i<players.length;i++){this.updatePlayerHealthUi(players[i]);this.updateCharacterMenuVisuals(players[i])}this.updateAllPlayerDamageStates();if(this.phase===GraveFallGame.scene.Game.PHASE_ACTION)this.layoutBattleAvatarsInArena()};
GraveFallGame.scene.Game.prototype.devCommandPlayerHeal=function(target){var players=this.resolveDevPlayers(target||"all");var i;if(players.length<=0)return"No matching player: "+target;for(i=0;i<players.length;i++){players[i].healthCurrent=players[i].healthMax;players[i].hideUntilNextEncounter=false;players[i].revivedFromEnemyDefeat=false;if(this.phase===GraveFallGame.scene.Game.PHASE_ACTION)this.activateBattleAvatar(players[i])}this.devRefreshPlayersAfterHealthChange(players);return"Healed players: "+
players.length};GraveFallGame.scene.Game.prototype.devCommandPlayerDown=function(target){var players=this.resolveDevPlayers(target||"all");var i;if(players.length<=0)return"No matching player: "+target;for(i=0;i<players.length;i++){players[i].healthCurrent=0;if(this.phase===GraveFallGame.scene.Game.PHASE_ACTION)this.deactivateBattleAvatar(players[i])}this.devRefreshPlayersAfterHealthChange(players);return"Downed players: "+players.length};
GraveFallGame.scene.Game.prototype.devCommandPlayerHp=function(target,amount){var players=this.resolveDevPlayers(target||"all");var hp=parseInt(amount,10);var i;if(players.length<=0)return"No matching player: "+target;if(isNaN(hp))return"Usage: gf.player.hp target amount";for(i=0;i<players.length;i++)players[i].healthCurrent=Math.max(0,Math.min(players[i].healthMax,hp));this.devRefreshPlayersAfterHealthChange(players);return"Set player HP for "+players.length+" players."};
GraveFallGame.scene.Game.prototype.resolveDevItemType=function(itemType){var search=String(itemType||"").toLowerCase();if(search==="all"||search==="*")return"all";if(search==="maxhp"||search==="max_hp"||search==="hp"||search==="health")return"maxHp";if(search==="attack"||search==="atk"||search==="damage")return"attack";if(search==="defense"||search==="defence"||search==="def"||search==="shield")return"defense";if(search==="speed"||search==="spd"||search==="move")return"speed";return null};
GraveFallGame.scene.Game.prototype.devGiveItems=function(players,itemType,count){var itemTypes=GraveFallGame.scene.Game.ITEM_BUFF_TYPES||["maxHp","attack","defense","speed"];var types=itemType==="all"?itemTypes:[itemType];var amount=Math.max(1,Math.min(99,count||1));var p;var t;var n;for(p=0;p<players.length;p++){if(!players[p].itemInventory)players[p].itemInventory={maxHp:0,attack:0,defense:0,speed:0};for(t=0;t<types.length;t++)for(n=0;n<amount;n++)this.givePlayerItem(players[p],types[t]);this.updateCharacterMenuVisuals(players[p])}};
GraveFallGame.scene.Game.prototype.devCommandItemAll=function(count){var players=this.resolveDevPlayers("all");var amount=parseInt(count,10);if(isNaN(amount))amount=1;this.devGiveItems(players,"all",amount);return"Gave every item x"+amount+" to every player."};
GraveFallGame.scene.Game.prototype.devCommandItemGive=function(target,itemType,count){var players=this.resolveDevPlayers(target||"all");var resolvedType=this.resolveDevItemType(itemType||"all");var amount=parseInt(count,10);if(players.length<=0)return"No matching player: "+target;if(!resolvedType)return"Usage: gf.item.give target item count";if(isNaN(amount))amount=1;this.devGiveItems(players,resolvedType,amount);return"Gave "+resolvedType+" x"+amount+" to "+players.length+" players."};
GraveFallGame.scene.Game.prototype.devCommandPhaseCommand=function(){this.devPrepareImmediateBattle();return"Entered command phase."};GraveFallGame.scene.Game.prototype.devCommandPhaseAction=function(){this.devEnsureActionPhaseForPatternTest();this.nextPatternIn=0;return"Entered action phase."};
GraveFallGame.scene.Game.prototype.devParsePositiveNumber=function(value,min,max){var number=parseFloat(value);if(isNaN(number))return null;if(typeof min==="number")number=Math.max(min,number);if(typeof max==="number")number=Math.min(max,number);return number};
GraveFallGame.scene.Game.prototype.devCommandTimerStatus=function(){var turnSeconds=this.getTurnTimerDurationMs()/1E3;var minigameSeconds=this.getMinigameDurationMs()/1E3;var actionFrames=this.getActionPhaseDurationFrames(this.getCurrentEnemyConfig());var currentTurn=typeof this.turnTimerMs==="number"?Math.ceil(this.turnTimerMs/1E3):0;return["Timers:","turn default seconds: "+turnSeconds,"turn remaining seconds: "+currentTurn,"minigame seconds: "+minigameSeconds,"action frames: "+actionFrames].join("\n")};
GraveFallGame.scene.Game.prototype.devCommandTimerTurn=function(seconds){var value=this.devParsePositiveNumber(seconds,1,300);if(value===null)return"Usage: gf.timer.turn seconds";GraveFallGame.scene.Game.DEV_TURN_TIMER_MS=Math.round(value*1E3);if(this.phase===GraveFallGame.scene.Game.PHASE_COMMAND)this.resetCommandTurnTimer(true,1);else if(this.turnTimerText)this.turnTimerText.text=this.getTurnTimerLabel();return"Turn timer default set to "+value+" seconds."};
GraveFallGame.scene.Game.prototype.devCommandTimerTurnLeft=function(seconds){var value=this.devParsePositiveNumber(seconds,0,300);if(value===null)return"Usage: gf.timer.turn.left seconds";this.turnTimerMs=Math.round(value*1E3);this.lastTurnWarningSecond=null;if(this.turnTimerText){this.turnTimerText.text=this.getTurnTimerLabel(this.turnTimerMs);this.turnTimerText.visible=this.phase===GraveFallGame.scene.Game.PHASE_COMMAND;this.turnTimerText.alpha=this.turnTimerText.visible?1:this.turnTimerText.alpha}return"Turn timer remaining set to "+
value+" seconds."};GraveFallGame.scene.Game.prototype.devCommandTimerAction=function(frames){var value=this.devParsePositiveNumber(frames,1,3600);if(value===null)return"Usage: gf.timer.action frames";GraveFallGame.scene.Game.DEV_ACTION_PHASE_FRAMES=Math.round(value);if(this.phase===GraveFallGame.scene.Game.PHASE_ACTION)this.actionPhaseTimer=Math.round(value);return"Action phase duration set to "+Math.round(value)+" frames."};
GraveFallGame.scene.Game.prototype.devCommandTimerMinigame=function(seconds){var value=this.devParsePositiveNumber(seconds,1,300);if(value===null)return"Usage: gf.timer.minigame seconds";GraveFallGame.scene.Game.DEV_MINIGAME_TIMER_MS=Math.round(value*1E3);if(this.phase===GraveFallGame.scene.Game.PHASE_MINIGAME){this.minigameTimer=Math.round(value*1E3);this.minigameDurationMs=this.minigameTimer}return"Minigame timer set to "+value+" seconds."};
GraveFallGame.scene.Game.prototype.devCommandTimerReset=function(){GraveFallGame.scene.Game.DEV_TURN_TIMER_MS=null;GraveFallGame.scene.Game.DEV_MINIGAME_TIMER_MS=null;GraveFallGame.scene.Game.DEV_ACTION_PHASE_FRAMES=null;if(this.phase===GraveFallGame.scene.Game.PHASE_COMMAND)this.resetCommandTurnTimer(true,1);return"Timer overrides reset."};
GraveFallGame.scene.Game.prototype.devRemoveTrackedDisplayList=function(listName){var list=this[listName];var removed=0;var i;if(!list){this[listName]=[];return 0}removed=list.length;for(i=list.length-1;i>=0;i--)if(list[i]&&list[i].parent)list[i].parent.removeChild(list[i],true);this[listName]=[];return removed};
GraveFallGame.scene.Game.prototype.devCleanTransientUi=function(){var minigamesRemoved=0;var i;var menu;if(this.playerMenus)for(i=0;i<this.playerMenus.length;i++){menu=this.playerMenus[i];if(menu&&menu.minigame){this.cleanupPlayerMinigame(menu);minigamesRemoved++}if(menu&&typeof this.restorePlayerActionPreviewShake==="function")this.restorePlayerActionPreviewShake(menu)}this.clearProjectiles();this.clearArenaItem();this.clearBuffVisualEffects();if(typeof this.clearActionPreviewState==="function")this.clearActionPreviewState();
if(typeof this.clearAllHealingStandAnimations==="function")this.clearAllHealingStandAnimations(true);if(typeof this.hideActionPrompt==="function")this.hideActionPrompt();if(typeof this.hideAllCharacterMenuTooltips==="function")this.hideAllCharacterMenuTooltips();this.delayedSfxQueue=[];this.devRemoveTrackedDisplayList("damagePopups");this.devRemoveTrackedDisplayList("scorePopups");return minigamesRemoved};
GraveFallGame.scene.Game.prototype.devRepairCurrentPhaseUi=function(){var i;var menu;var inCommand=this.phase===GraveFallGame.scene.Game.PHASE_COMMAND;var inAction=this.phase===GraveFallGame.scene.Game.PHASE_ACTION;var inDefeated=this.phase===GraveFallGame.scene.Game.PHASE_ENEMY_DEFEATED;var inGameOver=this.phase===GraveFallGame.scene.Game.PHASE_GAME_OVER;if(this.backgroundBackdrop)this.backgroundBackdrop.visible=!inGameOver;if(this.scoreText){this.scoreText.visible=!inGameOver;this.scoreText.alpha=
!inGameOver?1:0;this.updateScoreUi()}if(this.turnTimerText){this.turnTimerText.visible=inCommand;this.turnTimerText.alpha=inCommand?1:0;this.turnTimerText.text=this.getTurnTimerLabel(this.turnTimerMs)}this.setBattleArenaVisible(inAction);this.setPlayerActionMenusVisible(inCommand);this.updateEnemyHealthBarUi();this.updateEnemyDamageState();this.setEnemyUiAlpha(inDefeated||inGameOver?0:1);if(inCommand){this.resetPlayerMenusForCommandPhase();this.commandMenuResetDone=true;this.setPlayerTransitionVisibility(true,
true);this.setPlayerTransitionAlpha(1,1)}else if(inAction){this.setPlayerTransitionVisibility(false,false);this.layoutBattleAvatarsInArena();for(i=0;i<this.playerMenus.length;i++){menu=this.playerMenus[i];menu.container.y=menu.confirmedY;menu.hitCooldown=0;menu.moveSpeed=this.calculateEffectiveMoveSpeed(menu);this.activateBattleAvatar(menu)}}else if(!inGameOver){this.setPlayerTransitionVisibility(true,false);this.setPlayerTransitionAlpha(1,0)}this.updateAllPlayerDamageStates()};
GraveFallGame.scene.Game.prototype.devCommandUiClean=function(){var removed=this.devCleanTransientUi();if(this.enemyHealthCurrent<=0&&this.phase!==GraveFallGame.scene.Game.PHASE_ENEMY_DEFEATED){this.startEnemyDefeatedSequence();return"Cleaned UI and started enemy defeat sequence."}if(this.phase===GraveFallGame.scene.Game.PHASE_MINIGAME){this.startActionPreviewPhase();return"Cleaned minigame UI and advanced phase."}this.devRepairCurrentPhaseUi();return"Cleaned UI. Minigames removed: "+removed};
GraveFallGame.scene.Game.prototype.devCommandUiReset=function(){var removed=this.devCleanTransientUi();if(this.enemyHealthCurrent<=0){this.startEnemyDefeatedSequence();return"Reset UI and started enemy defeat sequence."}if(this.phase===GraveFallGame.scene.Game.PHASE_MINIGAME){this.startActionPreviewPhase();return"Reset minigame UI and advanced phase."}this.devRepairCurrentPhaseUi();return"Reset UI for current phase. Removed: "+removed};
GraveFallGame.scene.Game.prototype.devCommandScoreAdd=function(amount){var scoreAmount=parseInt(amount,10);if(isNaN(scoreAmount))return"Usage: gf.score.add amount";this.changeScore(scoreAmount);return"Score: "+this.score};GraveFallGame.scene.Game.prototype.devCommandScoreSet=function(amount){var scoreAmount=parseInt(amount,10);if(isNaN(scoreAmount))return"Usage: gf.score.set amount";this.score=Math.max(0,scoreAmount);this.updateScoreUi();return"Score: "+this.score};
