GraveFallGame.scene.Game.prototype.returnPlayerItemMenuToMain=function(playerMenu){playerMenu.menuState="main";playerMenu.selectedIndex=3;playerMenu.waitingForItemExitButtonRelease=true;this.playSfx(GraveFallGame.SOUNDS.UI_BACK,.55);this.updateCharacterMenuVisuals(playerMenu)};
